import React from "react";
import { useCurrency } from "../context/CurrencyContext";

export default function ProfileScreen({ user, onLogout, darkMode, toggleDarkMode }) {
  const { displayCurrency, setDisplayCurrency, supportedCurrencies } = useCurrency();

  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>
      <div className="flex justify-between items-center mb-6 pt-6">
        <h1 className="text-2xl font-bold">Profile</h1>
        <button onClick={toggleDarkMode}>
          {darkMode ? "🌞" : "🌙"}
        </button>
      </div>

      {/* User Info */}
      <div className={`rounded-2xl p-6 mb-6 shadow ${darkMode ? "bg-gray-800" : "bg-white"}`}>
        <p className="font-semibold text-lg">{user?.name || "Pips"}</p>
        <p className="text-sm text-gray-400">{user?.email || "user@example.com"}</p>
        <p className="text-xs text-gray-400 mt-1">Joined: {user?.joinedDate || "N/A"}</p>
      </div>

      {/* Currency Selector */}
      <div className={`rounded-2xl p-6 mb-6 shadow ${darkMode ? "bg-gray-800" : "bg-white"}`}>
        <h2 className="font-semibold text-lg mb-2">Select Currency</h2>
        <select
          value={displayCurrency}
          onChange={(e) => setDisplayCurrency(e.target.value)}
          className={`w-full p-3 rounded-lg border ${
            darkMode
              ? "bg-gray-700 border-gray-600 text-gray-100"
              : "bg-gray-50 border-gray-300 text-gray-900"
          }`}
        >
          {Object.keys(supportedCurrencies).map((code) => (
            <option key={code} value={code}>
              {code} — {supportedCurrencies[code].symbol}
            </option>
          ))}
        </select>
      </div>

      {/* Logout */}
      <button
        onClick={onLogout}
        className={`w-full py-3 rounded-xl font-semibold transition-colors ${
          darkMode
            ? "bg-red-600 hover:bg-red-700 text-white"
            : "bg-red-100 hover:bg-red-200 text-red-700"
        }`}
      >
        Logout
      </button>
    </div>
  );
}
